// Call this once; guarded by data.defaultDeckLoaded flag.
function installDefaultDeck() {
  if (!window.data) return;
  if (!Array.isArray(window.data.dictionary)) window.data.dictionary = [];
  if (window.data.defaultDeckLoaded) return 0;
  const today = (typeof todayStr === "function") ? todayStr() : new Date().toISOString().slice(0,10);
  let added = 0;
  for (const d of defaultDefinitions) {
    const exists = window.data.dictionary.some(w =>
      (w.jp && d.jp && w.jp === d.jp) ||
      (w.en && d.en && w.en.toLowerCase() === d.en.toLowerCase())
    );
    if (exists) continue;
    window.data.dictionary.push({
      en: d.en, jp: d.jp, es: d.es,
      tags: d.tags.slice(),
      type: "other",
      addedDate: today,
      uses: 0, correct: 0,
    });
    added++;
  }
  window.data.defaultDeckLoaded = true;
  if (typeof saveData === "function") saveData();
  if (typeof renderDictionary === "function") renderDictionary();
  if (typeof updateStats === "function") updateStats();
  console.log("[default-deck] installed", added, "entries");
  return added;
}

// Auto-install when DOM + data.js are ready
function tryInstallDefaultDeck() {
  if (typeof data === "undefined" || !window.data) { setTimeout(tryInstallDefaultDeck, 200); return; }
  installDefaultDeck();
}
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", () => setTimeout(tryInstallDefaultDeck, 50));
} else {
  setTimeout(tryInstallDefaultDeck, 50);
}
